8	  // Check username availability
9	  static Future<bool> checkUsername(String username) async {
10	    try {
11	      final response = await http.get(
12	        Uri.parse('$baseUrl/api/check-username?username=${Uri.encodeComponent(username)}'),
13	      );
14	      if (response.statusCode == 200) {
15	        return jsonDecode(response.body)['available'] == true;
16	      }
17	      return false;
18	    } catch (e) {
19	      return false;
20	    }
21	  }
