23	  // Register user
24	  static Future<bool> register(String username, String password) async {
25	    try {
26	      final response = await http.post(
27	        Uri.parse('$baseUrl/api/register'),
28	        headers: {'Content-Type': 'application/json'},
29	        body: jsonEncode({
30	          'username': username,
31	          'email': '$username@logindemo.com',
32	          'password': password,
33	        }),
34	      );
35	      return response.statusCode == 201;
36	    } catch (e) {
37	      return false;
38	    }
39	  }
