75	  // Get current user profile
76	  static Future<Map<String, dynamic>> getProfile() async {
77	    try {
78	      final token = await _getToken();
79	      final response = await http.get(
80	        Uri.parse('$baseUrl/api/users/me'),
81	        headers: {
82	          'Content-Type': 'application/json',
83	          if (token != null) 'Authorization': 'Bearer $token',
