94	  Future<List<_RankItem>> _fetchWhoILike() async {
95	    try {
96	      final resp = await http.get(
97	        Uri.parse('$_baseUrl/api/who_i_like'),
98	        headers: _headers,
99	      );
100	      if (resp.statusCode == 200) {
101	        final data = jsonDecode(resp.body) as Map<String, dynamic>;
102	        final users =
103	            (data['users'] as List<dynamic>).cast<Map<String, dynamic>>();
104	        return users
