148	  Future<void> _likeUser() async {
149	    if (_liked) {
150	      ScaffoldMessenger.of(context).showSnackBar(
151	        const SnackBar(content: Text('Already liked')),
152	      );
153	      return;
154	    }
155	
156	    if (!mounted) return;
157	    final audioPath = await showModalBottomSheet<String>(
158	      context: context,
159	      isScrollControlled: true,
160	      backgroundColor: Colors.transparent,
161	      builder: (ctx) => VoiceNoteRecorder(username: widget.username),
162	    );
163	
164	    if (audioPath == null) return;
165	
166	    try {
167	      final resp = await http.post(
168	        Uri.parse('$_baseUrl/api/like'),
169	        headers: _headers,
170	        body: jsonEncode({'liked_user_id': widget.userId}),
171	      );
172	      if (resp.statusCode == 200 || resp.statusCode == 201) {
173	        await _uploadVoiceNote(audioPath);
174	
175	        final body = jsonDecode(resp.body) as Map<String, dynamic>;
176	        final status = body['status'] as String?;
177	
178	        if (status == 'matched') {
179	          if (mounted) {
180	            ScaffoldMessenger.of(context).showSnackBar(
181	              const SnackBar(content: Text('🎉 It\'s a match!')),
182	            );
183	            Navigator.of(context).pop();
184	          }
185	        } else {
186	          setState(() => _liked = true);
187	
188	          final currentLikes = await _fetchWhoILike();
189	          final withoutNew =
190	              currentLikes.where((u) => u.id != widget.userId).toList();
191	          final items = [
192	            ...withoutNew,
193	            _RankItem(
194	              id: widget.userId,
195	              username: widget.username,
196	              age: widget.age,
197	              sex: widget.sex,
198	            ),
199	          ];
200	
201	          if (!mounted) return;
202	          await showModalBottomSheet<bool>(
203	            context: context,
204	            isScrollControlled: true,
205	            backgroundColor: const Color(0xFF0E0E0E),
206	            shape: const RoundedRectangleBorder(
207	              borderRadius: BorderRadius.vertical(top: Radius.circular(20)),
208	            ),
209	            builder: (ctx) => _RankingSheet(
210	              items: items,
211	              newUserId: widget.userId,
212	              baseUrl: _baseUrl,
213	              token: _token,
214	              onSave: (reordered) async {
215	                await _saveRerank(reordered);
216	                Navigator.of(ctx).pop(true);
217	              },
218	            ),
219	          );
220	        }
221	      }
222	    } catch (e) {
223	      if (mounted) {
224	        ScaffoldMessenger.of(context)
225	            .showSnackBar(SnackBar(content: Text('Like failed: $e')));
226	      }
227	    }
228	  }
