611	  Future<void> _togglePlay(int userId) async {
612	    if (_playing[userId] == true) {
613	      await _audioPlayer.stop();
614	      setState(() => _playing[userId] = false);
615	      return;
616	    }
617	
618	    if (!_voiceUrls.containsKey(userId)) {
619	      final url = await _fetchVoiceUrl(userId);
620	      setState(() => _voiceUrls[userId] = url);
621	    }
622	
623	    final url = _voiceUrls[userId];
624	    if (url == null) return;
625	
626	    await _audioPlayer.play(UrlSource(url));
627	    setState(() {
628	      for (final k in _playing.keys.toList()) {
629	        _playing[k] = false;
630	      }
631	      _playing[userId] = true;
632	    });
633	  }
